            return lastProcessedValue.get() > levelThreshold ? "HIGH" : "NORMAL";
        }
    });

    // 4. Apply a filter to the calculation using the filter method with a lambda that checks the difference
    statusCalc.filter([&](double currentValue, double lastValue) -> bool {
        return std::abs(currentValue - lastValue) > diffThreshold;
    });

