#pragma once

#include <reaction/reaction.h>

namespace test_reaction {

// ============================================
// Helper types
// ============================================

class RecordingNode : public reaction::ObserverNode {
public:
    void valueChanged(bool changed = true) override {
        m_notifications++;
        ObserverNode::valueChanged(changed);
    }

    int notificationCount() const {
        return m_notifications;
    }

private:
    int m_notifications = 0;
};

struct RollbackObservation {
    int notificationsAfterSecondBinding;
    int notificationsAfterRollback;
};

// ============================================
// Function implementation
// ============================================

RollbackObservation test_observer_state_rollback() {
    // 1. Create two RecordingNode instances
    RecordingNode firstSensor;
    RecordingNode secondSensor;

    // 2. Get the ObserverGraph instance
    auto& observerGraph = reaction::ObserverGraph::getInstance();

    // 3. Register both nodes
    observerGraph.addNode(&firstSensor);
    observerGraph.addNode(&secondSensor);

    // 4. Create initial dependency: firstSensor observes secondSensor
    observerGraph.addObserver(&firstSensor, &secondSensor);

    // 5. Save current state for rollback
    auto rollback = observerGraph.saveNodeStateForRollback(&firstSensor);

    // 6. Replace dependency transactionally
    // Remove current dependency and add new one
    observerGraph.removeObserver(&firstSensor, &secondSensor);
    observerGraph.addObserver(&secondSensor, &firstSensor); // Reverse dependency

    // 7. Trigger notification on second sensor
    secondSensor.valueChanged();

    // 8. Record notification count after second binding
    int countAfterSecondBinding = firstSensor.notificationCount();

    // 9. Execute rollback to restore original state
    rollback();

    // 10. Trigger notification on first sensor (now source)
    firstSensor.valueChanged();

    // 11. Record notification count after rollback
    int countAfterRollback = firstSensor.notificationCount();

    // 12. Return counts in RollbackObservation struct
    return {countAfterSecondBinding, countAfterRollback};
}

}  // namespace test_reaction
