 * @return StackAllocationSnapshot Snapshot of allocation checks before/after guard
 */
inline StackAllocationSnapshot test_stack_monitor_capacity(std::size_t largeSize) {
    StackAllocationSnapshot snapshot;

    // 1. Disable monitoring
    reaction::memory::StackMonitor::setMonitoring(false);

    // 2. Initialize stack monitor
    reaction::memory::StackMonitor::initialize();

    // 3. Check allocation without monitoring
    snapshot.smallAllowedWithoutMonitoring = reaction::memory::StackMonitor::canAllocate<reaction::memory::SBOConfig::ALWAYS_SBO_SIZE>();
    snapshot.largeAllowedWithoutMonitoring = reaction::memory::StackMonitor::canAllocate<reaction::memory::SBOConfig::CONDITIONAL_SBO_SIZE>();
    snapshot.runtimeAllowedWithoutMonitoring = reaction::memory::StackMonitor::canAllocate(largeSize);

    // 4. Enable monitoring
    reaction::memory::StackMonitor::setMonitoring(true);

    // 5. Initialize stack monitor again (idempotent operation)
    reaction::memory::StackMonitor::initialize();

    // 6. Check large allocation with monitoring
    snapshot.largeAllowedWithMonitoring = reaction::memory::StackMonitor::canAllocate<reaction::memory::SBOConfig::CONDITIONAL_SBO_SIZE>();

    // 7. Create StackGuard in scope block
    {
        reaction::memory::StackGuard<reaction::memory::SBOConfig::CONDITIONAL_SBO_SIZE> guard;

        // 8. Check if guard succeeded
        snapshot.guardSucceeded = guard.success();

        // 9. Check if allocation blocked at limit
        // Note: In practice, reaching the 64KB limit would require allocating ~64KB on stack,
        // which is typically not feasible in a test function. This demonstrates the principle.
        // For demonstration, we'll check if we can still allocate after the guard is active
        snapshot.allocationBlockedAtLimit = !reaction::memory::StackMonitor::canAllocate(largeSize);
    } // 10. Exit guard scope (automatic destruction)

    // 11. Check runtime allocation after release
    snapshot.runtimeAllowedAfterRelease = reaction::memory::StackMonitor::canAllocate(largeSize);

    // 12. Return stack allocation snapshot
    return snapshot;
}

